// 10. ENDNOTE PROPERTIES PER SECTION (ISO 29500-1 sections 17.11.2)
// ==========================================================================

/// ISO 29500-1 sections 17.11.2: Section-level endnotePr parsed correctly.
///
/// S1 has endnotes at sectEnd with upperRoman numbering.
/// S2 has endnotes at docEnd.
#[test]
fn spec_endnote_props_section_1() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "endnote-props-per-section");

    let section_props = section_paragraphs(&doc);
    assert!(!section_props.is_empty());

    let s1 = section_props[0];
    let en_pr = s1.endnote_pr.as_ref().expect("S1 should have endnote_pr");

    assert_eq!(
        en_pr.position,
        Some(stemma::domain::NotePosition::SectEnd),
        "S1 endnote position should be SectEnd, got {:?}",
        en_pr.position
    );
    assert_eq!(
        en_pr.num_fmt.as_ref().map(|f| f.to_xml_str()),
        Some("upperRoman"),
        "S1 endnote numFmt should be upperRoman, got {:?}",
        en_pr.num_fmt
    );
}

/// ISO 29500-1 sections 17.11.2: S2 has endnote position at docEnd.
#[test]
fn spec_endnote_props_section_2() {
    let (_rt, doc) = common::import_fixture(FIXTURES, "endnote-props-per-section");

    let body_sp = doc
        .body_section_properties
        .as_ref()
        .expect("body_section_properties should exist");

    let en_pr = body_sp
        .endnote_pr
        .as_ref()
        .expect("S2 should have endnote_pr");

    assert_eq!(
        en_pr.position,
        Some(stemma::domain::NotePosition::DocEnd),
        "S2 endnote position should be DocEnd, got {:?}",
        en_pr.position
    );
}
